<script setup lang="ts">/* RunningHubWalletNode */
import { ref, computed } from 'vue';import { Handle, Position } from '@vue-flow/core';import { useCanvasStore } from '@/stores/canvasStore'
const p=defineProps<{id:string;data:any;selected?:boolean;type?:string}>();const cs=useCanvasStore();const d=computed(()=>p.data||{})
const webappId=computed({get:()=>d.value.webappId||'',set:v=>cs.updateNodeData(p.id,{webappId:v})})
const prompt=computed({get:()=>d.value.prompt||'',set:v=>cs.updateNodeData(p.id,{prompt:v})})
function run(){window.dispatchEvent(new CustomEvent('jc-canvas-run-node',{detail:p.id}))}</script>
<template><div class="x" :class="{sel:selected}" :style="{borderColor:selected?'#a78bfa':'var(--border)'}"><Handle type="target" :position="Position.Left" :style="{background:'#a78bfa',width:10,height:10,border:'none'}"/><Handle type="source" :position="Position.Right" :style="{background:'#a78bfa',width:10,height:10,border:'none'}"/><div class="xh"><div class="xi" style="background:rgba(139,92,246,.18);color:#c4b5fd"><JcIcon name="wallet" style="font-size:13px" /></div><div class="xl">RH钱包应用</div></div><div class="xb" @mousedown.stop><input v-model="webappId" class="xi2" placeholder="WebApp ID"/><textarea v-model="prompt" class="xi2 xi3" placeholder="提示词..." rows="2"/><button class="xr2" :disabled="data.status==='running'" @click="run"><JcIcon name="auto_awesome" style="font-size:12px" />运行</button><div v-if="data.error" class="xe"><JcIcon name="error" style="font-size:11px" />{{data.error}}</div></div></div></template>
<style scoped>.x{width:300px;border:2px solid var(--border);border-radius:12px;background:var(--paper);box-shadow:var(--jc-shadow-sm);color:var(--ink1)}.x.sel{border-color:#a78bfa}.xh{display:flex;align-items:center;gap:8px;padding:8px 12px;border-bottom:1px solid var(--border2)}.xi{width:24px;height:24px;border-radius:6px;display:flex;align-items:center;justify-content:center}.xl{flex:1;font-size:13px;font-weight:600}.xb{padding:10px;display:flex;flex-direction:column;gap:8px}.xi2{width:100%;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--ink1);padding:5px 8px;font-size:11px;outline:none;font:inherit}.xi3{min-height:40px;resize:vertical}.xr2{width:100%;display:flex;align-items:center;justify-content:center;gap:6px;padding:6px;border-radius:6px;border:none;background:rgba(139,92,246,.2);color:#a78bfa;font-size:12px;font-weight:500;cursor:pointer}.xr2:disabled{opacity:.5}.xe{display:flex;align-items:flex-start;gap:4px;font-size:10px;color:#f87171;background:rgba(239,68,68,.1);border:1px solid rgba(239,68,68,.2);border-radius:4px;padding:4px 8px}</style>
